    ['Crying Over Onions'] = {
        id = 76,
        start_npc = 'Kohlo-Lakolo',
        start_zone = 'Port Windurst',
        start_pos = 'G-5',
        description = 'Honoi-gomoi, a merchant who lives in Windurst Waters, has ordered the Star Onion Brigade to return the Mana Orb to him. Help the gang out of this fix before they\'re framed as a bunch of thieves!',
        reward = 'Star Necklace',
