        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = {'Onion Rings'},
        next = {'Wild Card'},
        requirements = {
            {name = 'Star Spinel', count = 1},
        },
        walkthrough = '1. You\'ll need to zone again if you haven\'t done so yet after receiving Bouncer Club.\n2. Talk to Kohlo-Lakolo for a cut scene to start the quest.\n3. Head to southern Windurst Waters (a short walk away, or use Home Point #3) and speak to Honoi-Gomoi - (E-7) for a cut scene.\n   - He is upstairs in his house, which is accessed through a back stairway.\n4. Get a Star Spinel from Spelunking Sabotender in Quicksand Caves.\n   - Enter Quicksand Caves through the entrance in Western Altepa Desert at (G-5). Spelunking Sabotender can be found in the passageway near (F-7).\n   - There are also a couple spawns by Home Point #1.\n   - Sneak is required even at level 99.\n   - An Ornate Door blocks the way and can be opened via the weight pads nearby.  The weight pad requires a certain number of players to stand on it:\n     - 1 Galka\n     - Any 2 of Hume, Elvaan, or Mithra\n     - 3 Tarutaru\n     - Any 1 player after completing Open Sesame\n5. Bring the Star Spinel to Honoi-Gomoi, who will reward you with the Star Necklace after a cut scene.\n6. Talk to Kohlo-Lakolo for a cut scene, and then once again back to Honoi-Gomoi for a cut scene to complete the quest.',
        notes = nil,
    },
    ['Curses, Foiled A-Golem!?'] = {
        id = 63,
        start_npc = 'Shantotto',
        start_zone = 'Windurst Walls',
        start_pos = 'K-7',
        description = 'Shantotto wants you to go ask the Rhinostery\'s Rukususu about how her new magic is performing. Rukususu\'s party is said to be at the tower ruins on the Beaucedine Glacier.',
        reward = 'Scroll of Warp II',
        fame = 'Windurst',
        fame_level = '4',
        title = '*Doctor Shantotto\'s Flavor of the Month',
        repeatable = 'No',
        previous = {'Curses, Foiled...Again!?'},
