        requirements = {
            {name = '[Key Item] Shantotto\'s new spell', count = 1},
        },
        walkthrough = 'You must zone after completing the previous Quest.\n1. Speak to Shantotto (K-7) who will ask you a few questions.\n   - Choose the second option to the first question, "Ask if you\'re worthy."\n   - Choose the second option to the next question, "Whatchu talkin\' \'bout Shantotto?"\n     - If you answer "Yes mommy" to the second question, your title will change to "Total Loser". You can get the title from the Title Changer NPC after completing this Quest, even if you did not choose this option.\n2. Head to the tower at (I-7) in Beaucedine Glacier, speak to Torino-Samarino, speak to him again and choose the first option to receive [Key Item] Shantotto\'s new spell.\n3. Head to Fei\'Yin. In the basement (Map 2) at (F-6), check the north-western Cermet Door to get a cutscene with Rukususu.\n   - Using the Home Point #2 to Fei\'Yin is the fastest way.\n   - Note: Be careful of how many monsters you kill in Fei\'Yin. If you kill too many monsters while in posession of [Key Item] Shantotto\'s new spell before turning it in to Rukususu, the item will break and be replaced by [Key Item] Shantotto\'s ex-spell. If this happens, return to Torino-Samarino to retrieve another scroll.\n4. Return to Shantotto to complete the Quest and to receive your reward.',
        notes = '1. The completion of this Quest is one of the requirements to obtain Shantotto\'s Trust.',
    },
