    ['Escort for Hire (Windurst)'] = {
        id = 88,
        start_npc = 'Dehn Harzhapan',
        start_zone = 'Port Windurst',
        start_pos = 'G-6',
        description = 'You are to escort Wanzo-Unzozo to his desired destination within the Garlaige Citadel.',
        reward = 'First Completion: 10,000 Gil\nMiratete\'s Memoirs',
        fame = 'Windurst',
        fame_level = '6',
        title = nil,
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Completion certificate', count = 1},
        },
        walkthrough = '1. Speak to Dehn Harzhapan to begin the quest.\n2. Head to Garlaige Citadel.\n3. As soon as you zone in you will receive a cutscene.\n4. Once the cutscene is over, an NPC named Wanzo-Unzozo will spawn.\n   - Speaking to Wanzo-Unzozo will make him stop running. Talking to him again will make him continue.  He will aggro almost everything in the zone.\n   - Pay attention to Wanzo-Unzozo HP, if it gets too low he will aggro any undead inside.  He can be cured to prevent this.\n   - Just like monsters, Wanzo-Unzozo can run through the Banishing Gate so be sure to stop him before you open it, or have the Pouch of weighted stones.\n5. You will have 30 minutes to complete this quest.\n6. Escort Wanzo-Unzozo until he stops on his own.  Quickly talk to him to receive Completion certificate (Key Item).\n   - If he vanishes before you talk to him you will not get the key item and you will have to do this quest over again.\n7. Return to Dehn Harzhapan for your reward.',
        notes = nil,
    },
    ['Fire and Brimstone'] = {
