        start_npc = 'Kerutoto',
        start_zone = 'Windurst Waters South',
        start_pos = 'J-8',
        description = 'You\'ve been asked to buy food for the two busy researchers and one freshly-awoken meditator. You\'ll have to ask each of them what they want...if you can understand them, that is.',
