    },
    ['Hitting the Marquisate'] = {
        id = 71,
        start_npc = 'Nanaa Mihgo',
        start_zone = 'Windurst Woods',
        start_pos = 'J-3',
        description = 'Visit two of the eight active thieves gathered by the Tenshodo, and confirm the signatures of the people who originally wrote the documents in the "letter from the Tenshodo."',
        reward = 'Rogue\'s Poulaines',
        fame = 'Windurst',
        fame_level = nil,
        title = 'Paragon of Thief Excellence',
        repeatable = 'No',
        previous = {'As Thick as Thieves'},
        next = nil,
        requirements = {
            {name = 'Quake Grenade', count = 4},
            {name = 'Pickaxe', count = 1},
        },
        walkthrough = '1. Speak to Nanaa Mihgo in Windurst Woods (J-3) to receive the [Key Item] Cat Burglar\'s note.\n2. Go to Lower Jeuno (G-10) and speak to Yatniel on the top floor. He will ask for 4x Quake Grenades.\n3. Trade the Quake Grenades to him for a clue.\n   - NOTE: Although you can skip this part and get the [Key Item] Bomb incense and fight the Chandelier, you MUST turn in the Quake Grenades in order to clear the KI from Nanaa so she will allow you to complete the quest.\n4. Go to Mhaura (H-8) and speak to Hagain who is located in one of the upstairs rooms in the Sailor\'s Stay. He will give you the [Key Item] Bomb incense.\n5. Head to Garlaige Citadel via the main entrance.\n6. You will now need to examine multiple ??? in a specific order. Go to each one and choose "Yes" to use the [Key Item] Bomb incense.\n   - NOTE: Switching to first person view and locking on to the points make it easier to target them. The ??? is in the ceiling.\n   - Walk to I-9 near the first banishing gate for the first ???.\n   - Head west a bit and look around at H-9 for another ???.\n   - Go through the first Banishing Gate and follow the map down to F-9. The ??? to the west of the intersection is the one you want.\n   - Go across the hall to the east for another ??? at F/G-9.\n   - Go back the way you came, towards the Banishing Gate #1. Examine the ??? at G-8/9.\n   - Head to the north of this area for another ??? at G-7.\n   - Head east to pop the NM at the I-6 ???.\n   - READ BELOW BEFORE CLICKING THIS LAST ??\n7. The last ??? you\'ll examine will spawn a Bomb named Chandelier. This text below is confusing so I\'ll simplify, all you have to do is click ??? and then use Hide before the boss spawns so it doesn\'t self destruct. Then kill it normally.\n8. If it uses Self-Destruct before being claimed then it will not drop the Chandelier Coal.\n   - If it self-destructs before it is killed otherwise then there is a very minor chance it will drop.\n     - When this mob is spawned, if he is not claimed before he aggros, he will immediately self-destruct.\n     - If it spawns and sees a player character before it is claimed, he will immediately self-destruct.\n     - If it is spawned while a player is casting magic nearby, he will immediately self-destruct.\n9. If you fail to successfully claim him and he self-destructs then you will have to wait 10 minutes for the ??? to respawn.\n   - You do not have to go back and check all the ??? again.\n   - You DO have to go back and check all of the ??? again IF you leave the zone.\n10. Spectral Jig immediately after the cutscene is a great way to avoid detection.  Hide works as well.',
        notes = nil,
    },
