    ['Making Amens!'] = {
        id = 8,
        start_npc = 'Kuroido-Moido',
        start_zone = 'Port Windurst',
        start_pos = 'E-7',
        description = 'Hakkuru-Rinkuru\'s switching of Ajido- Marujido\'s broken wand has been discovered. It seems that the original wand had some special significance to the minister. Hurry and retrieve the original wand from the furnace in Garlaige Citadel before it\'s too late!',
