        requirements = {
            {name = '4x Yagudo Necklaces', count = 1},
        },
        walkthrough = '1. Speak to Nanaa Mihgo multiple times till the Quest is flagged.\n   - If done as a level 40+ Thief, it will potentially begin the Quests The Tenshodo Showdown (THF AF 1), As Thick as Thieves (THF AF 2) and/or Hitting the Marquisate (THF AF 3). You will need to finish these first to flag this Quest.\n   - (Optional): Speak to Cha Lebagta.\n2. You will have to obtain 4 Yagudo Necklaces.\n   - They can be purchased from the Auction House. ( ➞ Others ➞ Beast-made)\n   - Alternatively, they can be obtained by killing Yagudos () in Tahrongi Canyon or Giddeus.\n3. Trade Nanaa Mihgo the Necklaces to complete the Quest.',
        notes = '1. Completing this Quest raises your fame in Norg.\n   - It takes 53 completions of this Quest to raise your Norg fame to level 4, which is enough to start The Sahagin\'s Stash (Utsusemi: Ichi) and Trial by Water.\n2. The completion of this Quest is one of the requirements to obtain Nanaa Mihgo\'s Trust.',
    },
    ['Nothing Matters'] = {
        id = 79,
        start_npc = 'Koru-Moru',
        start_zone = 'Windurst Walls',
        start_pos = 'E-7',
        description = 'Professor Koru-Moru is currently engrossed in an experiment to create "something" out of "nothing." To get closer to the truth of alchemy, he wants you to track down an old "Thesis on Alchemy" for him.',
        reward = '10,000 Gil\nVile Elixir',
        fame = 'Windurst',
        fame_level = '8',
        title = 'Seeker of Truth',
        repeatable = nil,
        previous = {'Blast from the Past'},
        next = nil,
        requirements = nil,
        walkthrough = '1. Zone in and out if you just completed Blast from the Past.\n2. Speak to Koru-Moru to begin the quest.\n   - (Optional): Speak to Yoran-Oran (E-5) to discuss the author of the thesis on alchemy.\n   - (Optional): Speak to Shantotto (K-7) to discuss alchemy.\n3. Speak to Fuepepe in Windurst Waters North (L-6).\n4. Go north to the Acolyte Hostel (K-6). Interact with each of the six doors on the ground floor and you\'ll play Quiz de Vana\'diel. Answer a question correctly and go to another door until you have 4 to 6 correct answers. (See table at the bottom of this page.)\n5. After answering the questions, head to the western Acolyte Hostel building at (K-5) for a cutscene.\n6. You will receive the [Key Item] Thesis on alchemy.\n   - If you answered all 6 questions correctly, you\'ll additionally be rewarded a Vile Elixir.\n     - If you already have a Vile Elixir and should receive one, you won\'t be able to complete the quest. Zone out, dispose of your existing Vile Elixir, then come back to continue the quest/receive the cut-scene.\n   - If you answered 4 questions correctly, the quest will continue (but you will not receive an Elixir).\n7. Return to Koru-Moru for a cut-scene.\n8. Trade Koru-Moru a Cold Bone and Warm Egg for a cut-scene.\n   - Cold Bone can be purchased from the Auction House ( ➞ Materials ➞ Bonecraft) or farmed by killing Doom Soldier () that spawn at nighttime in Cape Teriggan. It is believed that the Doom Mages and Doom Soldiers share spawns with the goblins in the area, kill goblins at night to get Doom Soldier to spawn.\n   - Warm Egg can be purchased from the Auction House ( ➞ Food ➞ Ingredients) or farmed by killing Anemone () in Yhoator Jungle.\n9. Return to Koru-Moru in a few day-aroos (after Japanese Midnight) for your reward.',
        notes = nil,
    },
    ['One Good Deed?'] = {
        id = 92,
        start_npc = 'Chipmy-Popmy',
        start_zone = 'Port Windurst',
        start_pos = 'C-8',
        description = 'A mysterious character living on Purgonorgo Isle in Bibiki Bay insists that the island belongs to him. Chipmy-Popmy wants you to participate in the next "debate" over ownership, set to take place in the center of the island.',
        reward = 'Map of the Attohwa Chasm (if you do not already own it)\n2,000 Experience Points\n3,200 Gil',
