    ['The Fanged One'] = {
        id = 31,
        start_npc = 'Perih Vashai',
        start_zone = 'Windurst Woods',
        start_pos = 'K-7',
        description = 'In order to become a truly great hunter, one must be accepted by mother nature. In order for that to happen, one must gain the fang of a tiger, the fanged king. But it does not sound like any old fang will do...',
        reward = 'Ranger\'s Necklace\nAbility to become a Ranger.',
        fame = 'Windurst',
        fame_level = nil,
        title = 'The Fanged One',
        repeatable = 'No',
        previous = nil,
        next = {'Sin Hunting'},
        requirements = nil,
        walkthrough = '1. Speak to Perih Vashai in Windurst Woods at (K-7).\n   - She might mention something unrelated to this quest about Trusts ("If it\'s a scrrroll you seek, then I bid you talk to Shikaree Z.") the first time you talk to her each time upon zoning in. Just talk to her repeatedly until her dialogue is related instead to this quest.\n2. Travel to Sauromugue Champaign and find the cave at (L-10). To get there, go up the cliff at (L-8).  Examine the Tiger Bones in the cave to spawn the Old Sabertooth and watch it die naturally, a process which takes approximately three agonizing earth minutes.\n   - Easiest way to reach the cave is via the Survival Guide located at (J-9/J-10).\n3. Once the Old Sabertooth dies naturally, examine the Tiger Bones to get the [Key Item] Old tiger\'s fang.\n   - If you fight or otherwise disturb the Old Sabertooth you will not be able to get the key item.\n   - If you do not click the Tiger Bones in a reasonable amount of time after death, you will have to click on the Tiger Bones and watch it die naturally again.\n4. Return to Perih Vashai to complete the quest.',
        notes = nil,
    },
    ['The Moonlit Path'] = {
        id = 9,
        start_npc = 'Leepe-Hoppe',
        start_zone = 'Windurst Waters South',
        start_pos = 'J-9',
        description = 'Leepe-Hoppe wants you to take on Carbuncle\'s request to gather the six "whispers," then pay a visit to the Full Moon Fountain...',
        reward = 'Ability to summon Fenrir or\nAbility to summon Fenrir as a Mount or\nAncients\' Key or\nFenrir\'s Cape or\nFenrir\'s Earring or\nFenrir\'s Stone or\nFenrir\'s Torque or\n15,000 gil',
        fame = 'Windurst',
        fame_level = '6',
        title = 'Heir of the New Moon',
        repeatable = 'Yes',
        previous = {
            'Trial by Earth',
            'Trial by Fire',
            'Trial by Ice',
            'Trial by Lightning',
            'Trial by Water',
            'Trial by Wind',
        },
        next = nil,
        requirements = {
            {name = 'Whisper of flames', count = 1},
            {name = 'Whisper of frost', count = 1},
            {name = 'Whisper of gales', count = 1},
            {name = 'Whisper of storms', count = 1},
            {name = 'Whisper of tides', count = 1},
            {name = 'Whisper of tremors', count = 1},
        },
        walkthrough = '1. Talk to Leepe-Hoppe to begin the quest. If the quest Tuning In is offered (cutscene with Shikaree Y), simply zone and talk to Leepe-Hoppe again to get the proper cutscene. Assuming you have the proper fame.\n2. Next you must battle the six avatar primes to collect their whispers.\n3. Turn the whispers into Leepe-Hoppe to receive a Moon bauble.\n4. Head to Full Moon Fountain.\n   - Preferably, home point to Toraimarai Canal #1. If you don\'t have it yet, make sure to grab it on the way. Otherwise, the Survival Guide can be used to warp to Toraimarai Canal if you have it.\n5. With the Moon bauble key item in your possession, interact with the fountain to enter the battlefield.\n6. Defeat Fenrir Prime and you will receive the key item: Whisper of the moon.\n7. Return to Leepe-Hoppe to turn in the whisper for your reward.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own [Key Item] Moon bauble.\n3. Time limit is 30 minutes.\n4. You can only select one of the rewards Leepe-Hoppe offers at any time.\n5. You may repeat this quest once per Earth day.\n6. Once you have completed this quest you can return to Leepe-Hoppe for another Moon bauble. Reobtaining the whispers is not required.',
    },
