    ['The Puppet Master'] = {
        id = 81,
        start_npc = 'Carbuncle',
        start_zone = 'Windurst Walls',
        start_pos = 'G-4',
        description = 'According to the words of Carbuncle, the thief that is stealing the avatars\' energy from adventurers is currently in Bastok. You must travel to Bastok to confront the situation.',
        reward = 'Kukulcan\'s Staff',
        fame = 'Windurst',
        fame_level = '1',
        title = nil,
        repeatable = 'No',
        previous = {'I Can Hear a Rainbow'},
        next = {'Class Reunion'},
        requirements = {
            {name = 'Earth Pendulum', count = 1},
        },
        walkthrough = '1. While you are on Summoner as a main job, interact with the House of the Hero in Windurst Walls (Home Point #1) to speak to Carbuncle.\n2. Speak to Juroro in Port Bastok at (I-8) (Home Point #1). Ildy-Goldy will give you an Earth Pendulum.\n3. Make your way through the Quicksand Caves to the Cloister of Tremors. Home Point #2 is at the entrance.\n   - If this is your first time visiting Cloister of Tremors, follow these directions:\n     - Enter Quicksand Caves via Eastern Altepa Desert at (K-7).\n     - Using the map below (click to enlarge), observe the red arrows. These are one-way drops.\n     - Walk to (C-9) by dropping down twice the correct directions.\n::\n4. Trade the Earth Pendulum to the Protocrystal to enter the battle field.\n   - Inside you must defeat Galgalim, which is Level 56.\n     - Trusts can be summoned.\n     - Has Fire Spikes, Poison and a Paralyze.\n5. Speak to Juroro again.\n6. Speak to Koru-Moru in Windurst Walls at (E-7) to complete the quest and receive your reward.\n   - You can drop the Earth Pendulum after completing the quest, as it serves no further purpose.',
        notes = nil,
    },
    ['The Root of the Problem'] = {
        id = 68,
        start_npc = 'Chumimi',
        start_zone = 'Heavens Tower',
        start_pos = nil,
        description = 'The cause of the star trees\' poor growth seems to lie in the Toraimarai Canal.  First, bring some silk cloth to Profressor Koru-Moru so he can improve his magic doll.  Then take the magic doll into the Toraimarai Canal to carry out an inspection.',
        reward = 'Wizard\'s Petasos',
        fame = 'Windurst',
        fame_level = '1',
        title = 'Paragon of Black Mage Excellence',
        repeatable = 'No',
        previous = {'Recollections'},
        next = nil,
        requirements = {
            {name = 'Silk Cloth', count = 1},
            {name = '[Key Item] "Sluice Surveyor Mk. I"', count = 1},
        },
        walkthrough = '1. Begin quest by speaking with Chumimi as Black Mage in the basement of Heavens Tower.\n   - Zoning out of the tower is required after finishing the previous quest.\n2. After the cutscene, trade a Silk Cloth to Koru-Moru (E-7) in Windurst Walls.\n3. Return to Chumimi afterwards to recieve the [Key Item] "Sluice Surveyor Mk. I".\n4. Proceed to Toraimarai Canal and locate two ??? points.\n   - Manafont is required so make sure you are on Black Mage.\n   - You must examine the point when it is in front of you.\n     - If you are too far away or on the opposite side of the concrete grate, you will receive a message that you cannot examine further.\n5. The first ??? is in the North-east corner of (H-7) on map 1.\n   - From the Survival Guide follow the left wall until you come to a grate blocking the path. The "???" Will be right there.\n6. The second ??? is at (I-9) on (map 1).\n7. At one of the ??? you\'ll get a cutscene then be asked for "the Mage\'s black power".\n   - Use  Manafont, then check the ??? again for another cutscene.\n   - This is usually the second point you examine, however there is a very low chance that the first point can require it too.\n   - You do not need to be on Black Mage for the rest of the quest\n8. Go to (J-8) and click on the ??? for a cutscene and to pop Magic Sludge, a Dark Elemental NM.\n   - There are 2 ??? right beside each other here. The correct one is the one that is not glowing.\n   - The NM is highly resistant to physical damage and magic to a lesser extent.\n9. If there are multiple BLMs in the same party, the NM credit will only go to whoever initiates the CS to pop it.\n   - There is a 3 minute waiting period before another NM can be spawned after it is killed.\n10. Click the ??? again for another cutscene\n11. Return to Chumimi for the final cutscene and your reward.',
        notes = nil,
    },
    ['The Tenshodo Showdown'] = {
        id = 69,
        start_npc = 'Nanaa Mihgo',
        start_zone = 'Windurst Woods',
        start_pos = 'J-3',
        description = 'The Tenshodo is gathering expert thieves to its fold. Carry out your orders by handing the Tenshodo envelopes to the appropriate people and having them sign the documents within.',
        reward = 'Marauder\'s Knife',
        fame = 'Windurst',
        fame_level = nil,
        title = nil,
        repeatable = 'No',
        previous = nil,
        next = {'As Thick as Thieves'},
        requirements = {
            {name = 'Quadav Stew', count = 1},
        },
        walkthrough = '1. Talk to Nanaa Mihgo as a Thief to begin this quest, and she will give you a [Key Item] Letter from the Tenshodo.\n   - You must have the Tenshodo Membership to continue with this quest.\n2. Head to Lower Jeuno and talk to Harnek inside of the Tenshodo at (J-7) for a cutscene.\n3. You will be given the [Key Item] Tenshodo envelope.\n4. Travel to Selbina and talk to Elfriede (J-9) of the Shepherd\'s Muster Inn. You will receive a cutscene with Sneaking Tiger who will ask for a Quadav Stew.\n5. Quadav Stew can only be stolen from certain Quadavs in Beadeaux.\n   - The stew can be stolen BEFORE you go to Selbina to save yourself some time.\n6. Head to Beadeaux and steal from Garnet Quadav, Silver Quadav, Zircon Quadav, and Bronze Quadav until you obtain the Quadav Stew.\n7. Once you get the Quadav Stew, go back to Selbina and trade the stew to Elfriede (J-9).\n8. You will receive the [Key Item] Signed envelope.\n9. Head back to Lower Jeuno and talk to Harnek (J-7) for a final cutscene and to receive your reward.',
        notes = '1. Having Windurst Mission 2-1 active will prevent you from starting this quest.\n2. Nanaa Mihgo is involved in several quests/misions, you may have to talk to her multiple times to trigger the correct cutscene.',
    },
    ['The Three Magi'] = {
        id = 66,
        start_npc = 'Chumimi',
        start_zone = 'Heavens Tower (bottom floor)',
        start_pos = nil,
        description = 'The star tree saplings at the farm in the basement of Heavens Tower aren\'t growing very well. Doctor Shantotto and co. have ordered an investigation to try and solve the problem. Help them by bringing back a glowstone from the crevasse of Xarcabard.',
        reward = 'Casting Wand',
        fame = 'Windurst',
        fame_level = '1',
        title = 'One of the following:',
        repeatable = 'No',
        previous = nil,
        next = {'Recollections'},
        requirements = {
            {name = 'Faded Crystal', count = 1},
        },
        walkthrough = '1. Begin the quest by speaking with Chumimi, found in the basement of Heavens Tower (Windurst).\n   - You must be on Black Mage to start this quest.\n   - During this cutscene you will be asked to agree with one of the three NPCs. Whomever you pick will decide your title, but otherwise will not affect your quest.\n2. After speaking with Chumimi, head to any Telepoint and trade a synthesis crystal to receive a Faded Crystal.\n3. Travel to Xarcabard and head toward (E-8)\n4. Find a ??? marker in the glowing trenches.\n   - This is very close to the Castle Zvahl Baileys zone. Easiest way to get here is via the Castle Zvahl Baileys Survival Guide and just zoning out to Xarcabard.\n5. Trade your Faded Crystal and spawn the Chaos Elemental.\n   - The Chaos Elemental is a Light Elemental, therefore it is resistant to all physical damage. A party of 6 at level 40 should be able to kill it.\n   - If multiple people are doing the quest you will need to wait 3 min after it dies to pop again.\n6. Take the Glowstone that drops from the NM and return to Chumimi.\n   - She will give you the Casting Wand in return.',
        notes = nil,
    },
    ['To Bee or Not to Bee?'] = {
        id = 35,
        start_npc = 'Raamimi',
        start_zone = 'Windurst Walls',
        start_pos = 'F-7',
        description = 'Zayhi-Bauhi, the old man who constantly gives public speeches by the bridge to Heavens Tower, has come down with a sore throat. Follow Raamimi\'s advice on how to soothe this little pain in the neck.',
        reward = 'Mulsum x3',
        fame = 'Windurst',
        fame_level = '2',
        title = nil,
        repeatable = nil,
        previous = {'The Postman Always K.O.s Twice'},
        next = nil,
        requirements = nil,
        walkthrough = '1. If Zayhi-Bauhi speaks normally rather than coughing, try speaking to Kalupa-Tawalupa and Rutango-Botango in front of him to receive the quest.\n2. Speak to Raamimi to receive Honey.\n3. Trade Honey to Zayhi-Bauhi, then speak to Kalupa-Tawalupa and Rutango-Botango.\n4. Trade 4 more Honey, one at a time, to Zayhi-Bauhi.\n5. Return to Raamimi to receive 3 Mulsum.',
        notes = nil,
    },
    ['To Catch a Falling Star'] = {
        id = 53,
        start_npc = 'Sigismund',
        start_zone = 'Port Windurst',
        start_pos = 'E-7',
        description = 'Sigismund wants you to bring him a "Starfall Tear" so he can take it back to his country as a souvenir of Windurst.',
        reward = 'Fish Scale Shield',
        fame = 'Windurst',
        fame_level = '1',
        title = nil,
        repeatable = 'No',
        previous = nil,
        next = nil,
        requirements = {
            {name = 'Pugil Scales', count = 1},
            {name = 'Starfall Tear', count = 1},
        },
        walkthrough = '1. To start this quest, speak to Sigismund on top of the Orastery at (E-7) of Port Windurst. He tells you about the elusive Starfall Tear.\n2. Speak with Tohopka, who is standing right next to Sigismund, at (E-7). Tohopka tells you how to collect the tears. You\'ll need to obtain some Pugil Scales.  Pugils drop them, or you can find them under the AH category Bonecrafting. If there are no Scales on the AH, you can kill Pugils just outside in East Sarutabaruta for some.\n3. You can also find the Starfall Tear on the AH under the "Other" category.\n4. With some Scales in you possession, head out to West Sarutabaruta. On the map, there is a place called the "Starfall Hillock."  In the general vicinity of that area, at (I-6), you will find the Twinkle Tree.  If you\'re having trouble finding the tree, it\'s a somewhat rounded tree that has a blue firefly-type glow during the nighttime.\n5. Wait until the hours of 0:00 to 3:00 game time. At any other time, the tree gives the message "There is nothing out of the ordinary here," but during those three hours you\'ll receive another message: "A frost deposit at the base of the tree twinkles in the starlight."  At this point, trade the Pugil Scales and you\'ll receive your Starfall Tear.\n6. Head back to Sigismund and give him the Tears.  He gives you a Fish Scale Shield as a reward.',
        notes = nil,
    },
