    ['Waking Dreams'] = {
        id = 93,
        start_npc = 'Kerutoto',
        start_zone = 'Windurst Waters South',
        start_pos = 'J-8',
        description = 'Diabolos has informed Kerutoto that he is waiting for you at the Shrouded Maw in Pso\'Xja, buried deep in the northern lands. You must respond to his summons so that Kerutoto can meditate free of trouble.',
        reward = 'Diabolos (Avatar)\n15,000 Gil\nDiabolos\'s Pole \nDiabolos\'s Earring \nDiabolos\'s Torque \nDiabolos\'s Ring',
        fame = 'Windurst',
        fame_level = '3',
        title = 'Heir to the Realm of Dreams',
        repeatable = 'Yes',
        previous = nil,
        next = nil,
        requirements = nil,
        walkthrough = '1. Speak to Kerutoto, Windurst Waters South (J-8) HP #3, for a cutscene that begins the quest and key item Vial of dream incense.\n   - Windurst Waters Home Point #3 is just south of Kerutoto.\n2. Head to Pso\'Xja Home Point #1.\n   - If you do not yet have the Home Point:\n     - Travel to Beaucedine Glacier (H-8) and enter Pso\'Xja.\n     - The Beaucedine Glacier Survival Guide brings you at H-9, just south of the entrance to Pso\'Xja.\n     - Once inside the correct displacement sequence is red, purple, red, then purple; you will lose all buffs each time you go through the displacements.\n     - Take the elevator down, then head forward and head left at the intersection.\n     - Use the Stone Gate and select Yes when asked to use the Pso\'Xja pass[Key Item].\n     - The Home Point is just past the gate on the left.\n3. Head down the steps into The Shrouded Maw.\n4. Select the Memento Circle and pick Waking Dreams.\n5. Defeat Diabolos Prime to receive a key item: Whisper of dreams.\n   - Diabolos Prime has the following spells and abilities:\n     - Drain\n     - Aspir\n     - Sleepga II\n     - Dispelga\n     - Blindga\n     - Noctoshield- grants Diabolos the effect of "Phalanx."\n     - Dream Shroud- Enhances magic attack and magic defense of Diabolos.\n     - Camisado- Deals physical damage.\n     - Nether Blast- Delivers a ranged attack that deals darkness elemental damage.\n     - Ultimate Terror- Decreases attributes of players within area of effect.\n     - Nightmare- Deals darkness elemental damage that puts all enemies within the area of effect to sleep and gradually reduces their HP.\n     - Ruinous Omen- Astral Flow ability- Reduces the HP of enemies within the area of effect by a random percentage.\n   - Tiles on the battlefield will vanish during the battle, dropping players to a Diremites-filled death.\n6. Return to Kerutoto with the whisper and she will provide several reward options including the ability to summon Diabolos.',
        notes = '1. Up to 6 party members can enter the arena.\n2. Each party member must have their own [Key Item] Vial of dream incense\n3. Time limit is 30 minutes\n4. You can only select 1 of the rewards Kerutoto offers at any time\n5. You may repeat this quest once per Earth day.\n6. When clearing for the first time, the event with Diabolos in The Shrouded Maw will change depending on your progress in Chains of Promathia Missions.',
    },
